import React from 'react';
import { AlertTriangle, Droplets, MapPinned, Timer } from 'lucide-react';

function riskMeta(intensity) {
  const v = String(intensity || '').toUpperCase();
  if (v === 'VEHICLE_RISK') {
    return { label: 'Vehicle Risk', color: 'bg-red-500/15 text-red-200 ring-red-500/25' };
  }
  if (v === 'KNEE') {
    return { label: 'Knee Level', color: 'bg-yellow-400/15 text-yellow-100 ring-yellow-400/25' };
  }
  return { label: 'Ankle Level', color: 'bg-emerald-400/15 text-emerald-100 ring-emerald-400/25' };
}

export default function ReportSidebar({
  reports,
  loading,
  onPickReport,
  onOpenReport,
  routing,
}) {
  return (
    <div className="w-[360px] max-w-[calc(100vw-32px)] rounded-2xl border border-white/10 bg-slate-950/75 p-4 shadow-soft backdrop-blur">
      <div className="flex items-start justify-between gap-4">
        <div>
          <div className="text-base font-semibold">Active Flood Alerts</div>
          <div className="mt-1 text-xs text-slate-400">Reports from the last 24 hours</div>
        </div>
        <div className="rounded-xl bg-white/5 px-2 py-1 text-xs text-slate-300 ring-1 ring-white/10">
          {loading ? 'Loading…' : `${reports.length} alerts`}
        </div>
      </div>

      <div className="mt-4 rounded-2xl border border-white/10 bg-black/20 p-3">
        <div className="flex items-center gap-2 text-xs text-slate-300">
          <MapPinned size={14} className="text-slate-400" />
          <span className="font-medium">Safe Routing</span>
        </div>
        <div className="mt-2 grid gap-2">
          <input
            value={routing.origin}
            onChange={(e) => routing.setOrigin(e.target.value)}
            placeholder="Origin (e.g., Ameerpet)"
            className="w-full rounded-xl border border-slate-700/60 bg-slate-950/50 px-3 py-2 text-sm text-slate-100 placeholder:text-slate-500 outline-none focus:border-sky-500/60"
          />
          <input
            value={routing.destination}
            onChange={(e) => routing.setDestination(e.target.value)}
            placeholder="Destination (e.g., Hitech City)"
            className="w-full rounded-xl border border-slate-700/60 bg-slate-950/50 px-3 py-2 text-sm text-slate-100 placeholder:text-slate-500 outline-none focus:border-sky-500/60"
          />
          <button
            type="button"
            onClick={routing.onFindRoute}
            disabled={!routing.enabled}
            className="rounded-xl bg-sky-500 px-3 py-2 text-sm font-semibold text-slate-950 transition hover:bg-sky-400 disabled:cursor-not-allowed disabled:opacity-60"
          >
            Find Safe Route
          </button>
          {routing.status ? (
            <div className="flex items-start gap-2 text-xs text-slate-300">
              <AlertTriangle size={14} className="mt-0.5 text-slate-400" />
              <div>{routing.status}</div>
            </div>
          ) : null}
        </div>
      </div>

      <div className="mt-4 grid gap-2">
        {reports.map((r) => {
          const meta = riskMeta(r.intensity || r.waterLevel);
          return (
            <button
              key={r._id || `${r.lat}-${r.lng}-${r.timestamp || r.time}`}
              type="button"
              onClick={() => onPickReport?.(r)}
              className="group w-full rounded-2xl border border-white/10 bg-black/20 px-3 py-3 text-left transition hover:bg-black/30"
            >
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <Droplets size={16} className="text-slate-400" />
                    <div className="truncate text-sm font-semibold text-slate-100">
                      {r.placeName || r.address || 'Reported Flooding'}
                    </div>
                  </div>
                  <div className="mt-1 flex items-center gap-2 text-xs text-slate-400">
                    <Timer size={14} />
                    <span>{r.timeAgo || '—'}</span>
                  </div>
                </div>
                <span className={`shrink-0 rounded-xl px-2 py-1 text-[11px] ring-1 ${meta.color}`}>
                  {meta.label}
                </span>
              </div>
            </button>
          );
        })}
      </div>

      <button
        type="button"
        onClick={onOpenReport}
        className="mt-4 w-full rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-slate-950 transition hover:bg-slate-100"
      >
        Submit New Report
      </button>
    </div>
  );
}
